// ── Group Classifier ──
export const ofpGetGroup = c => {
  if (c.includes("Splint") || c.includes("Appliance") || c.includes("NTI")) return "Splints & Appliances";
  if (c.includes("Acupuncture") || c.includes("BFA") || c.includes("Auricular")) return "Acupuncture & BFA";
  if (c.includes("PBM") || c.includes("Photobiomodulation") || c.includes("Ultrasound")) return "Physical Modalities";
  if (c.includes("Injection") || c.includes("Trigger Point") || c.includes("Nerve Block")) return "Injection Techniques";
  if (c.includes("Pharmacology") || c.includes("Drug")) return "Pharmacology";
  if (c.includes("Protocol") || c.includes("Algorithm")) return "Protocols";
  return "Other";
};

export const OFP_GROUPS = ["Splints & Appliances", "Acupuncture & BFA", "Physical Modalities", "Injection Techniques", "Pharmacology", "Protocols"];

